// Suppress flicker (ADR-0003: confidence floor 0.6) and emit only transitions
// as AlarmV1 payloads. The mqtt_to_sqlite gateway persists these to alarms.
const FLOOR = 0.6;
const p = msg.payload;
if (p == null || p.confidence == null || p.confidence < FLOOR) return null;
const key = p.asset_id || 'unknown';
const last = context.get('last_' + key);
if (p.state === last) return null;
context.set('last_' + key, p.state);
msg.topic = `pdm/${key}/alarm`;
msg.payload = {
  schema_ver: 1,
  asset_id: key,
  ts_utc: p.ts_utc,
  from: last || null,
  to: p.state,
  confidence: p.confidence
};
return msg;

// 60-second rolling fraction of HEALTHY samples per asset.
const WINDOW_MS = 60 * 1000;
const p = msg.payload;
const key = p.asset_id || 'unknown';
const now = Date.parse(p.ts_utc) || Date.now();
const buf = context.get('buf_' + key) || [];
buf.push({ ts: now, healthy: p.state === 'HEALTHY' ? 1 : 0 });
while (buf.length && now - buf[0].ts > WINDOW_MS) buf.shift();
context.set('buf_' + key, buf);
const h = buf.reduce((a, b) => a + b.healthy, 0);
msg.topic = `pdm/${key}/oee`;
msg.payload = { window_s: WINDOW_MS / 1000, availability: h / buf.length, samples: buf.length };
return msg;
